import React, { useRef, useEffect, useState, useCallback } from 'react';
import { useTranslation } from '../i18n/index';
import { XMarkIcon, PencilIcon, BarcodeIcon } from './Icons';
import { useAppSettings } from '../contexts/AppSettingsContext';

interface CameraCaptureProps {
  onCapture: (imageDataUrl: string) => void;
  onClose: () => void;
  mode?: 'main' | 'ingredients' | 'receipt';
  onSwitchToManual?: () => void;
  onSwitchToBarcode?: () => void;
}

export const CameraCapture: React.FC<CameraCaptureProps> = ({ onCapture, onClose, mode = 'main', onSwitchToManual, onSwitchToBarcode }) => {
  const { t } = useTranslation();
  const { isBarcodeScannerEnabled } = useAppSettings();
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraReady, setIsCameraReady] = useState(false);
  const [focusPoint, setFocusPoint] = useState<{ x: number, y: number } | null>(null);

  const setupCamera = useCallback(async () => {
    if (streamRef.current) return;

    try {
      // Höhere Auflösung anfordern für maximale Schärfe
      const constraints = {
        video: { 
          facingMode: 'environment',
          width: { ideal: 4096 }, // 4K ideal
          height: { ideal: 2160 },
          focusMode: 'continuous' // Nur manche Browser/Systeme unterstützen das direkt in den Initial Constraints
        } as any,
        audio: false,
      };

      const mediaStream = await navigator.mediaDevices.getUserMedia(constraints);

      // Fokus-Optimierung nach dem Start
      const track = mediaStream.getVideoTracks()[0];
      const capabilities = track.getCapabilities() as any;

      // Falls das Gerät erweiterten Autofokus unterstützt, aktivieren wir ihn
      if (capabilities.focusMode && capabilities.focusMode.includes('continuous')) {
        try {
          await track.applyConstraints({
            advanced: [{ focusMode: 'continuous' }]
          } as any);
        } catch (e) {
          console.warn("Konnte kontinuierlichen Autofokus nicht erzwingen", e);
        }
      }

      streamRef.current = mediaStream;
      if (videoRef.current) {
        videoRef.current.srcObject = mediaStream;
        videoRef.current.onloadedmetadata = () => {
          setIsCameraReady(true);
        };
      }
    } catch (err: any) {
      console.error("Fehler beim Zugriff auf die Kamera:", err);
      setError(t('camera.error'));
    }
  }, [t]);

  useEffect(() => {
    setupCamera();
    return () => {
      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
        streamRef.current = null;
      }
    };
  }, [setupCamera]);

  // Funktion um den Fokus manuell zu triggern (Tap-to-Focus Simulation)
  const handleTapToFocus = async (e: React.MouseEvent | React.TouchEvent) => {
    if (!streamRef.current) return;

    const track = streamRef.current.getVideoTracks()[0];
    const capabilities = track.getCapabilities() as any;

    // Koordinaten für die visuelle Anzeige berechnen
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    setFocusPoint({ x: clientX - rect.left, y: clientY - rect.top });
    setTimeout(() => setFocusPoint(null), 1000);

    // Wenn das Gerät manuellen Fokus unterstützt
    if (capabilities.focusMode && capabilities.focusMode.includes('manual')) {
        try {
            await track.applyConstraints({
                advanced: [{ focusMode: 'manual' }] // Kurz umschalten triggert oft eine Neuausrichtung
            } as any);
            // Kurz darauf zurück auf kontinuierlich für beste User Experience
            setTimeout(async () => {
                await track.applyConstraints({
                    advanced: [{ focusMode: 'continuous' }]
                } as any);
            }, 500);
        } catch (e) {
            console.warn("Fokus-Constraint fehlgeschlagen", e);
        }
    }
  };

  const handleCapture = () => {
    if (videoRef.current && canvasRef.current && isCameraReady) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      if (ctx) {
        // Wir nutzen die native Auflösung des Videos für den Crop
        const videoW = video.videoWidth;
        const videoH = video.videoHeight;
        const minDim = Math.min(videoW, videoH);

        let cropW, cropH, startX, startY;

        if (mode === 'main') {
            const cropSize = minDim * 0.85; 
            cropW = cropSize;
            cropH = cropSize;
        } else if (mode === 'ingredients') {
            cropW = minDim * 0.8;
            cropH = cropW * 1.33;
        } else {
            cropH = videoH * 0.9; 
            cropW = cropH * 0.5;
        }

        startX = (videoW - cropW) / 2;
        startY = (videoH - cropH) / 2;

        canvas.width = cropW;
        canvas.height = cropH;

        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = 'high';

        ctx.drawImage(video, startX, startY, cropW, cropH, 0, 0, canvas.width, canvas.height);

        const imageDataUrl = canvas.toDataURL('image/jpeg', 0.95); // Hohe Qualität beim Speichern
        onCapture(imageDataUrl);
      }
    }
  };

  const getOverlayStyle = () => {
      switch(mode) {
          case 'main': return 'aspect-square w-[85vw] max-w-[80vh] rounded-2xl';
          case 'ingredients': return 'aspect-[3/4] w-[75vw] max-w-[60vh] rounded-lg';
          case 'receipt': return 'aspect-[1/2] h-[80vh] max-w-[90vw] rounded-lg border-dashed';
          default: return 'aspect-square w-[80vw]';
      }
  };

  return (
    <div className="fixed inset-0 bg-black bg-opacity-95 flex flex-col items-center justify-center z-50 overflow-hidden">
      <div className="absolute top-0 left-0 w-full p-4 z-20 flex justify-between items-center bg-gradient-to-b from-black/50 to-transparent">
         <h3 className="text-lg font-bold text-white drop-shadow-md">{t('camera.title')}</h3>
         <button onClick={onClose} className="text-white hover:text-gray-300 p-2 rounded-full hover:bg-white/10 transition-colors">
            <XMarkIcon className="w-8 h-8" />
         </button>
      </div>

      {error ? (
        <div className="text-red-400 p-8 text-center max-w-xs bg-red-900/20 rounded-xl border border-red-900/50">{error}</div>
      ) : (
        <div 
          className="relative w-full h-full flex items-center justify-center cursor-crosshair"
          onClick={handleTapToFocus}
          onTouchStart={handleTapToFocus}
        >
          <video
            ref={videoRef}
            autoPlay
            playsInline
            muted
            className="absolute inset-0 w-full h-full object-cover"
          />

          {/* Fokus-Indikator Animation */}
          {focusPoint && (
            <div 
                className="absolute border-2 border-yellow-400 rounded-lg w-16 h-16 pointer-events-none z-30 animate-focus-pulse"
                style={{ left: focusPoint.x - 32, top: focusPoint.y - 32 }}
            ></div>
          )}

          {/* Dark Overlay with Scan Window */}
          <div className="absolute inset-0 pointer-events-none flex items-center justify-center">
             <div className={`relative border-2 border-white/50 shadow-[0_0_0_9999px_rgba(0,0,0,0.6)] transition-all duration-300 ${getOverlayStyle()}`}>
                <div className="absolute top-[-2px] left-[-2px] w-8 h-8 border-t-4 border-l-4 border-indigo-400 rounded-tl-2xl"></div>
                <div className="absolute top-[-2px] right-[-2px] w-8 h-8 border-t-4 border-r-4 border-indigo-400 rounded-tr-2xl"></div>
                <div className="absolute bottom-[-2px] left-[-2px] w-8 h-8 border-b-4 border-l-4 border-indigo-400 rounded-bl-2xl"></div>
                <div className="absolute bottom-[-2px] right-[-2px] w-8 h-8 border-b-4 border-r-4 border-indigo-400 rounded-br-2xl"></div>

                <div className="absolute -bottom-10 left-0 right-0 text-center">
                    <span className="text-white/90 text-sm font-medium bg-black/40 px-4 py-1.5 rounded-full backdrop-blur-md">
                        Tippen zum Fokussieren
                    </span>
                </div>
             </div>
          </div>

          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}

      <div className="absolute bottom-0 left-0 w-full p-8 z-20 flex justify-between items-center bg-gradient-to-t from-black/80 via-black/40 to-transparent">
        <div className="flex-1 flex justify-start">
            {onSwitchToManual && (
                <button onClick={onSwitchToManual} className="flex flex-col items-center gap-1 text-white/70 hover:text-white transition-colors p-2">
                    <div className="p-3 bg-white/10 rounded-full backdrop-blur-md border border-white/10">
                        <PencilIcon className="w-6 h-6" />
                    </div>
                </button>
            )}
        </div>

        <button
          onClick={handleCapture}
          disabled={!isCameraReady || !!error}
          className="w-20 h-20 bg-white rounded-full border-4 border-gray-400 shadow-2xl flex items-center justify-center hover:bg-gray-100 active:scale-90 transition-all disabled:opacity-50 mx-4"
        >
            <div className="w-16 h-16 bg-white rounded-full border-2 border-black/80"></div>
        </button>

        <div className="flex-1 flex justify-end">
            {isBarcodeScannerEnabled && onSwitchToBarcode && (
                <button onClick={onSwitchToBarcode} className="flex flex-col items-center gap-1 text-white/70 hover:text-white transition-colors p-2">
                    <div className="p-3 bg-white/10 rounded-full backdrop-blur-md border border-white/10">
                        <BarcodeIcon className="w-6 h-6" />
                    </div>
                </button>
            )}
        </div>
      </div>
      <style>{`
        @keyframes focusPulse {
            0% { transform: scale(1.2); opacity: 1; }
            100% { transform: scale(1); opacity: 0; }
        }
        .animate-focus-pulse {
            animation: focusPulse 0.5s ease-out forwards;
        }
      `}</style>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { FoodItem, NutriScore, GroceryCategory, Receipt, ReceiptItem } from "../types";
import { AiFoodAnalysisSchema, AiIngredientsAnalysisSchema, AiReceiptSchema } from "./schemas";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const hasValidApiKey = (): boolean => {
    return !!process.env.API_KEY;
};

export function getAiClient() {
    if (!process.env.API_KEY) {
        throw new Error("API key not found. Please ensure it's set in your environment variables.");
    }
    return ai;
}

// QUALITY GATE: Image Optimization - Erhöhte Auflösung für bessere Schärfe bei der KI
const resizeImage = (base64Str: string, mode: 'main' | 'text' | 'receipt' = 'main'): Promise<string> => {
    let maxWidth = 1280; // Von 1024 auf 1280 erhöht
    let quality = 0.9; // Qualität von 0.85 auf 0.9 erhöht

    if (mode === 'main') {
        maxWidth = 1280;
        quality = 0.9;
    } else if (mode === 'text') {
        maxWidth = 1600; // Text braucht mehr Details
        quality = 0.85;
    } else if (mode === 'receipt') {
        maxWidth = 1600;
        quality = 0.85;
    }

    return new Promise((resolve) => {
        const img = new Image();
        img.src = base64Str;
        img.onload = () => {
            let width = img.width;
            let height = img.height;

            if (width > maxWidth) {
                height = Math.round((height * maxWidth) / width);
                width = maxWidth;
            }

            const canvas = document.createElement('canvas');
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            if (ctx) {
                ctx.imageSmoothingEnabled = true;
                ctx.imageSmoothingQuality = 'high';
                ctx.drawImage(img, 0, 0, width, height);
                resolve(canvas.toDataURL('image/jpeg', quality));
            } else {
                resolve(base64Str);
            }
        };
        img.onerror = () => {
            resolve(base64Str);
        };
    });
};

const parseJsonFromString = (text: string) => {
    const jsonMatch = text.match(/```json\s*([\s\S]*?)\s*```/);
    if (jsonMatch && jsonMatch[1]) {
        return JSON.parse(jsonMatch[1]);
    }
    try {
        return JSON.parse(text);
    } catch (e) {
        const arrayMatch = text.match(/(\[[\s\S]*\])/);
        if (arrayMatch && arrayMatch[1]) {
            try { return JSON.parse(arrayMatch[1]); } catch (p) {}
        }
        const objectMatch = text.match(/(\{[\s\S]*\})/);
        if (objectMatch && objectMatch[1]) {
             try { return JSON.parse(objectMatch[1]); } catch (p) {}
        }
    }
    throw new Error("Could not parse JSON from the AI response.");
};

export interface BoundingBox {
    x: number;
    y: number;
    width: number;
    height: number;
}

export const analyzeFoodImage = async (base64Image: string): Promise<{ name: string; tags: string[]; nutriScore?: NutriScore; boundingBox?: BoundingBox; itemType?: 'product' | 'drugstore' | 'dish'; category?: GroceryCategory; image: string }> => {
  const resizedImage = await resizeImage(base64Image, 'main');
  const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
  if (!match) throw new Error("Invalid base64 image string.");
  const mimeType = match[1];
  const data = match[2];

  try {
    const gemini = getAiClient();
    const imagePart = { inlineData: { mimeType, data } };
    const textPart = {
      text: "Identify item. Name: Extract EXACT brand + product text. Type: 'product', 'drugstore', 'dish'. Category: produce, bakery, meat_fish, dairy_eggs, pantry, frozen, snacks, beverages, household, personal_care, restaurant_food, other. Tags: max 5 keywords. Nutri-Score (A-E). BoundingBox: DETECT EXACT PIXEL BOUNDARIES of the single main object.",
    };

    const response = await gemini.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts: [imagePart, textPart] },
      config: {
        temperature: 0.1,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            itemType: { type: Type.STRING, enum: ['product', 'drugstore', 'dish'] },
            category: { type: Type.STRING, enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'] },
            tags: { type: Type.ARRAY, items: { type: Type.STRING } },
            nutriScore: { type: Type.STRING },
            boundingBox: {
              type: Type.OBJECT,
              properties: {
                  ymin: { type: Type.NUMBER },
                  xmin: { type: Type.NUMBER },
                  ymax: { type: Type.NUMBER },
                  xmax: { type: Type.NUMBER },
              },
              required: ["ymin", "xmin", "ymax", "xmax"]
            }
          },
          required: ["name", "tags", "itemType", "category"],
        },
      },
    });

    const rawResult = parseJsonFromString(response.text);

    // ZOD VALIDATION
    const parsedResult = AiFoodAnalysisSchema.safeParse(rawResult);

    if (!parsedResult.success) {
        console.warn("AI Validation Failed", parsedResult.error);
        throw new Error("AI response did not match expected schema.");
    }

    const result = parsedResult.data;

    let boundingBox: BoundingBox | undefined;
    if (result.boundingBox) {
        const img = new Image();
        img.src = resizedImage;
        await new Promise(r => { img.onload = r; });
        const w = img.width;
        const h = img.height;
        boundingBox = {
            x: (result.boundingBox.xmin / 1000) * w,
            y: (result.boundingBox.ymin / 1000) * h,
            width: ((result.boundingBox.xmax - result.boundingBox.xmin) / 1000) * w,
            height: ((result.boundingBox.ymax - result.boundingBox.ymin) / 1000) * h
        };
    }
    return { 
        name: result.name || '', 
        tags: result.tags || [], 
        nutriScore: (result.nutriScore as NutriScore) || undefined, 
        itemType: (result.itemType as any) || 'product',
        category: (result.category as any) || 'other',
        boundingBox, 
        image: resizedImage 
    };
  } catch (error) {
    console.error("Error analyzing food image:", error);
    throw error;
  }
};

export const analyzeIngredientsImage = async (base64Image: string): Promise<{ ingredients: string[]; allergens: string[]; isLactoseFree: boolean; isVegan: boolean; isGlutenFree: boolean; }> => {
    const resizedImage = await resizeImage(base64Image, 'text');
    const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
    if (!match) throw new Error("Invalid base64 image string.");
    const mimeType = match[1];
    const data = match[2];
    try {
      const gemini = getAiClient();
      const imagePart = { inlineData: { mimeType, data } };
      const textPart = { text: "Extract ingredients/INCI. List allergens. Boolean checks: isLactoseFree, isVegan, isGlutenFree." };
      const response = await gemini.models.generateContent({
        model: "gemini-2.5-flash",
        contents: { parts: [imagePart, textPart] },
        config: {
          temperature: 0,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              ingredients: { type: Type.ARRAY, items: { type: Type.STRING } },
               allergens: { type: Type.ARRAY, items: { type: Type.STRING } },
              isLactoseFree: { type: Type.BOOLEAN },
              isVegan: { type: Type.BOOLEAN },
              isGlutenFree: { type: Type.BOOLEAN },
            },
            required: ["ingredients", "allergens", "isLactoseFree", "isVegan", "isGlutenFree"],
          },
        },
      });
      const rawResult = parseJsonFromString(response.text);

      // ZOD VALIDATION
      const parsed = AiIngredientsAnalysisSchema.safeParse(rawResult);
      if (!parsed.success) {
          console.warn("Ingredients validation failed", parsed.error);
          return { ingredients: [], allergens: [], isLactoseFree: false, isVegan: false, isGlutenFree: false };
      }

      return {
          ingredients: parsed.data.ingredients || [],
          allergens: parsed.data.allergens || [],
          isLactoseFree: !!parsed.data.isLactoseFree,
          isVegan: !!parsed.data.isVegan,
          isGlutenFree: !!parsed.data.isGlutenFree
      };
    } catch (error) {
      console.error("Error analyzing ingredients image:", error);
      throw error;
    }
  };

export const findNearbyRestaurants = async (latitude: number, longitude: number): Promise<{ name: string; cuisine?: string }[]> => {
  try {
    const gemini = getAiClient();
    const response = await gemini.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts: [{ text: "Find 5 nearby restaurants. Return JSON array: [{name, cuisine}]." }] },
      config: {
        temperature: 0.1,
        tools: [{googleMaps: {}}],
        toolConfig: { retrievalConfig: { latLng: { latitude, longitude } } }
      }
    });
    const result = parseJsonFromString(response.text);
    return Array.isArray(result) ? result : [];
  } catch (error) {
    console.error("Error finding nearby restaurants:", error);
    throw error;
  }
};

export const performConversationalSearch = async (query: string, items: FoodItem[]): Promise<string[]> => {
  if (!query || items.length === 0) return [];
  const optimizedItems = items.map(item => ({
      id: item.id,
      n: item.name,
      t: item.itemType,
      c: item.category,
      r: item.rating,
      nt: item.notes,
      tg: item.tags
  }));
  try {
    const gemini = getAiClient();
    const response = await gemini.models.generateContent({
      model: "gemini-2.5-flash",
      config: {
        temperature: 0.2,
        systemInstruction: "Search engine. Return IDs of items that match query. Keys: n=name, nt=notes, tg=tags.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: { matchingIds: { type: Type.ARRAY, items: { type: Type.STRING } } },
          required: ["matchingIds"],
        },
      },
      contents: { parts: [{ text: `Query: "${query}"\nData: ${JSON.stringify(optimizedItems)}` }] },
    });
    return parseJsonFromString(response.text).matchingIds || [];
  } catch (error) {
    console.error("Error performing conversational search:", error);
    throw error;
  }
};

export const parseShoppingList = async (input: string): Promise<{ name: string; quantity: number; category: GroceryCategory }[]> => {
    try {
        const gemini = getAiClient();
        const response = await gemini.models.generateContent({
            model: "gemini-2.5-flash",
            contents: { parts: [{ text: `Extract items from this shopping list: "${input}". JSON.` }] },
            config: {
                temperature: 0,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    name: { type: Type.STRING },
                                    quantity: { type: Type.NUMBER },
                                    category: { type: Type.STRING, enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'] }
                                },
                                required: ["name", "quantity", "category"]
                            }
                        }
                    },
                    required: ["items"]
                }
            }
        });
        const result = parseJsonFromString(response.text);
        return result.items || [];
    } catch (error) {
        console.error("Error parsing shopping list:", error);
        throw error;
    }
};

// --- IMPROVED RECEIPT ANALYSIS WITH CONTEXT ---

export const analyzeReceiptImage = async (
    base64Image: string, 
    shoppingListContext: { id: string, name: string }[] = []
): Promise<Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] }> => {
    const resizedImage = await resizeImage(base64Image, 'receipt');
    const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
    if (!match) throw new Error("Invalid base64 image string.");
    const mimeType = match[1];
    const data = match[2];

    // Prepare context prompt
    let contextStr = "";
    if (shoppingListContext.length > 0) {
        contextStr = `\nI have recently bought items from my shopping list. Try to map receipt lines to these IDs if they match semantically: ${JSON.stringify(shoppingListContext)}`;
    }

    try {
        const gemini = getAiClient();
        const response = await gemini.models.generateContent({
            model: "gemini-2.5-flash",
            contents: {
                parts: [
                    { inlineData: { mimeType, data } },
                    { text: `Analyze this receipt. Extract merchant, date (YYYY-MM-DD), currency, total. Extract line items (name, price, quantity). Categorize: produce, bakery, meat_fish, dairy_eggs, pantry, frozen, snacks, beverages, household, personal_care, restaurant_food, other.${contextStr}\nIf a line item on the receipt matches an item from the provided shopping list context, return its 'id' in the 'food_item_id' field for that item.` }
                ]
            },
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        merchant_name: { type: Type.STRING },
                        date: { type: Type.STRING },
                        total_amount: { type: Type.NUMBER },
                        currency: { type: Type.STRING },
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    raw_name: { type: Type.STRING },
                                    price: { type: Type.NUMBER },
                                    quantity: { type: Type.NUMBER },
                                    category: { type: Type.STRING, enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'] },
                                    food_item_id: { type: Type.STRING, description: "The ID from the context if matched." }
                                },
                                required: ["raw_name", "price", "category"]
                            }
                        }
                    },
                    required: ["merchant_name", "total_amount", "items"]
                }
            }
        });

        const rawResult = parseJsonFromString(response.text);

        // ZOD VALIDATION
        const parsed = AiReceiptSchema.safeParse(rawResult);
        if (!parsed.success) {
             console.warn("Receipt validation failed", parsed.error);
             throw new Error("Validation failed");
        }

        const result = parsed.data;

        return {
            merchant_name: result.merchant_name,
            date: result.date || new Date().toISOString().split('T')[0],
            total_amount: result.total_amount || 0,
            currency: result.currency || 'EUR',
            items: (result.items || []) as Partial<ReceiptItem>[]
        };
    } catch (error) {
