// --- IMPROVED RECEIPT ANALYSIS WITH CONTEXT ---

export const analyzeReceiptImage = async (
    base64Image: string, 
    shoppingListContext: { id: string, name: string }[] = []
): Promise<Omit<Partial<Receipt>, 'items'> & { items: Partial<ReceiptItem>[] }> => {
    const resizedImage = await resizeImage(base64Image, 'receipt');
    const match = resizedImage.match(/^data:(image\/[a-z]+);base64,(.*)$/);
    if (!match) throw new Error("Invalid base64 image string.");
    const mimeType = match[1];
    const data = match[2];

    // Prepare context prompt
    let contextStr = "";
    if (shoppingListContext.length > 0) {
        contextStr = `\nI have recently bought items from my shopping list. Try to map receipt lines to these IDs if they match semantically: ${JSON.stringify(shoppingListContext)}`;
    }

    try {
        const gemini = getAiClient();
        const response = await gemini.models.generateContent({
            model: "gemini-2.5-flash",
            contents: {
                parts: [
                    { inlineData: { mimeType, data } },
                    { text: `Analyze this receipt. Extract merchant, date (YYYY-MM-DD), currency, total. Extract line items (name, price, quantity). Categorize: produce, bakery, meat_fish, dairy_eggs, pantry, frozen, snacks, beverages, household, personal_care, restaurant_food, other.${contextStr}\nIf a line item on the receipt matches an item from the provided shopping list context, return its 'id' in the 'food_item_id' field for that item.` }
                ]
            },
            config: {
                temperature: 0.1,
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        merchant_name: { type: Type.STRING },
                        date: { type: Type.STRING },
                        total_amount: { type: Type.NUMBER },
                        currency: { type: Type.STRING },
                        items: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    raw_name: { type: Type.STRING },
                                    price: { type: Type.NUMBER },
                                    quantity: { type: Type.NUMBER },
                                    category: { type: Type.STRING, enum: ['produce', 'bakery', 'meat_fish', 'dairy_eggs', 'pantry', 'frozen', 'snacks', 'beverages', 'household', 'personal_care', 'restaurant_food', 'other'] },
                                    food_item_id: { type: Type.STRING, description: "The ID from the context if matched." }
                                },
                                required: ["raw_name", "price", "category"]
                            }
                        }
                    },
                    required: ["merchant_name", "total_amount", "items"]
                }
            }
        });

        const rawResult = parseJsonFromString(response.text || '{}');

        // ZOD VALIDATION
        const parsed = AiReceiptSchema.safeParse(rawResult);
        if (!parsed.success) {
             console.warn("Receipt validation failed", parsed.error);
             throw new Error("Validation failed");
        }

        const result = parsed.data;

        return {
            merchant_name: result.merchant_name,
            date: result.date || new Date().toISOString().split('T')[0],
            total_amount: result.total_amount || 0,
            currency: result.currency || 'EUR',
            items: (result.items || []) as Partial<ReceiptItem>[]
        };
    } catch (error) {
        console.error("Error analyzing receipt:", error);
        throw error;
    }
}

import { Type } from "@google/genai";
import { getAiClient, hasValidApiKey } from './geminiService';

// Constants
const CACHE_KEY = 'food_tracker_translation_cache';
const SOURCE_LANGUAGE = 'en';
const BATCH_DELAY_MS = 100; // Wait 100ms to collect requests

// Helper to load cache from localStorage
const loadCache = (): Record<string, Record<string, string>> => {
    try {
        const stored = localStorage.getItem(CACHE_KEY);
        return stored ? JSON.parse(stored) : {};
    } catch (e) {
        console.error("Failed to load translation cache", e);
        return {};
    }
};

// Helper to save cache to localStorage
const saveCache = (cache: Record<string, Record<string, string>>) => {
    try {
        localStorage.setItem(CACHE_KEY, JSON.stringify(cache));
    } catch (e) {
        console.error("Failed to save translation cache", e);
    }
};

// Initialize in-memory cache from storage
const memoryCache: Record<string, Record<string, string>> = loadCache();

// --- Batching State ---
interface PendingRequest {
    text: string;
    targetLang: 'de'; // Currently strictly 'de' as source is 'en', but extensible
    resolve: (translated: string) => void;
    reject: (error: any) => void;
}

let pendingQueue: PendingRequest[] = [];
let batchTimeout: ReturnType<typeof setTimeout> | null = null;

// The actual API caller processing the batch
const processBatch = async () => {
    if (pendingQueue.length === 0) return;

    // 1. Take snapshot of current queue and clear global
    const currentBatch = [...pendingQueue];
    pendingQueue = [];
    batchTimeout = null;

    // 2. Group by language (though we primarily support en->de now)
    const requestsByLang: Record<string, PendingRequest[]> = {};
    currentBatch.forEach(req => {
        if (!requestsByLang[req.targetLang]) requestsByLang[req.targetLang] = [];
        requestsByLang[req.targetLang].push(req);
    });

    // 3. Process per language
    for (const [lang, requests] of Object.entries(requestsByLang)) {
        // Deduplicate texts to save tokens
        const uniqueTexts = Array.from(new Set(requests.map(r => r.text)));

        // Filter out what might have been cached in the meantime
        const textsToFetch = uniqueTexts.filter(text => {
            return !memoryCache[lang]?.[text];
        });

        if (textsToFetch.length === 0) {
            // Everything is in cache, just resolve
            requests.forEach(req => {
                const cached = memoryCache[lang]?.[req.text] || req.text;
                req.resolve(cached);
            });
            continue;
        }

        try {
            const gemini = getAiClient();
            const langName = lang === 'de' ? 'German' : 'English';

            // Send ONE request for ALL texts
            const response = await gemini.models.generateContent({
                model: "gemini-2.5-flash",
                config: {
                    // QUALITY GATE: Temperature 0 ensures deterministic translations.
                    temperature: 0, 
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            translations: {
                                type: Type.ARRAY,
                                items: {
                                    type: Type.OBJECT,
                                    properties: {
                                        original: { type: Type.STRING },
                                        translated: { type: Type.STRING }
                                    },
                                    required: ["original", "translated"]
                                }
                            }
                        }
                    }
                },
                contents: {
                    parts: [{
                        text: `Translate array to ${langName}. Preserve casing.` +
                        `\nInput: ${JSON.stringify(textsToFetch)}`
                    }]
                },
            });

            // Parse Response
            const json = JSON.parse(response.text || '{"translations":[]}');
            const mapping: Record<string, string> = {};

            if (json.translations && Array.isArray(json.translations)) {
                json.translations.forEach((t: any) => {
                    if (t.original && t.translated) {
                        mapping[t.original] = t.translated;
                    }
                });
            }

            // Update Cache
            if (!memoryCache[lang]) memoryCache[lang] = {};
            let cacheUpdated = false;

            textsToFetch.forEach(text => {
                // If API missed it, fallback to original
                const result = mapping[text] || text;
                memoryCache[lang][text] = result;
                cacheUpdated = true;
            });

            if (cacheUpdated) saveCache(memoryCache);

            // Resolve all promises
            requests.forEach(req => {
                const result = memoryCache[lang][req.text] || req.text;
                req.resolve(result);
            });

        } catch (error) {
            console.error("Batch translation failed:", error);
            // Fallback: Resolve with original text instead of crashing app
            requests.forEach(req => req.resolve(req.text));
        }
    }
};


export const translateTexts = async (texts: (string | undefined | null)[], targetLang: 'en' | 'de'): Promise<string[]> => {
    // 1. Optimization: If target is source language, return immediately.
    if (targetLang === SOURCE_LANGUAGE) {
        return texts.map(t => t || '');
    }

    // 2. Optimization: Filter out empty/null strings early
    if (!texts || texts.length === 0) {
        return [];
    }

    // Check if we even have an API key before trying remote translation
    if (!hasValidApiKey()) {
        return texts.map(t => t || '');
    }

    if (!memoryCache[targetLang]) {
        memoryCache[targetLang] = {};
    }

    // Prepare result array
    const results: string[] = new Array(texts.length);
    const promises: Promise<void>[] = [];

    texts.forEach((text, index) => {
        const trimmedText = typeof text === 'string' ? text.trim() : '';

        if (!trimmedText) {
            results[index] = '';
            return;
        }

        // Check Cache Immediately
        if (memoryCache[targetLang][trimmedText]) {
            results[index] = memoryCache[targetLang][trimmedText];
            return;
        }

        // If not in cache, add to Batch Queue
        const p = new Promise<string>((resolve, reject) => {
            pendingQueue.push({
                text: trimmedText,
                targetLang: targetLang as 'de', 
                resolve,
                reject
            });
        }).then(translated => {
            results[index] = translated;
        });

        promises.push(p);
    });

    // Start Timer if not running
    if (pendingQueue.length > 0 && !batchTimeout) {
        batchTimeout = setTimeout(processBatch, BATCH_DELAY_MS);
    }

    // Wait for all queued items to be resolved by the batch processor
    if (promises.length > 0) {
        await Promise.all(promises);
    }

    return results;
};

import React, { useState, useCallback } from 'react';
import { GoogleGenAI } from '@google/genai';
import { useTranslation } from '../i18n/index';
import { SparklesIcon } from './Icons';

interface ApiKeyTesterProps {
    onKeyVerified: (apiKey: string) => void;
    buttonText?: string;
}

export const ApiKeyTester: React.FC<ApiKeyTesterProps> = ({ onKeyVerified, buttonText }) => {
    const { t } = useTranslation();
    const [apiKey, setApiKey] = useState('');
    const [status, setStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState<string | null>(null);
    const [isInvalidKeyError, setIsInvalidKeyError] = useState(false);

    const handleTestKey = useCallback(async () => {
        const keyToTest = apiKey.trim();
        if (!keyToTest) return;

        setStatus('testing');
        setErrorMessage(null);
        setIsInvalidKeyError(false);

        try {
            const testAi = new GoogleGenAI({ apiKey: keyToTest });
            await testAi.models.generateContent({ 
                model: 'gemini-2.5-flash', 
                contents: { parts: [{ text: 'hello' }] }
            });

            setStatus('success');
            // If successful, call the callback to notify the parent.
            onKeyVerified(keyToTest);

        } catch (e: any) {
            setStatus('error');

            // Improved error message extraction to handle different error formats from the API.
            let message = 'An unknown error occurred.';
            if (e?.error?.message) {
                message = e.error.message;
            } else if (e instanceof Error) {
                message = e.message;
            } else if (typeof e === 'string') {
                message = e;
            }

            if (message.includes('API key not valid') || message.includes('API_KEY_INVALID')) {
                setIsInvalidKeyError(true);
            }

            setErrorMessage(message.replace(/\[\w+\/\w+\]\s*/, ''));
            console.error("API Key Test Failed:", e);
        }
    }, [apiKey, onKeyVerified]);

    const getStatusMessage = () => {
        switch (status) {
            case 'testing':
                return (
                    <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                        <SparklesIcon className="w-4 h-4 animate-pulse" />
                        <span>{t('settings.apiKeyTest.status.testing')}</span>
                    </div>
                );
            case 'success':
                return <p className="text-sm text-green-600 dark:text-green-400">{t('settings.apiKeyTest.status.success')}</p>;
            case 'error':
                if (isInvalidKeyError) {
                    return (
                        <p className="text-sm text-red-500 dark:text-red-400">
                            {t('settings.apiKeyTest.status.error.invalidKey.start')}
                            <a 
                                href="https://aistudio.google.com/app/apikey" 
                                target="_blank" 
                                rel="noopener noreferrer" 
                                className="underline hover:text-red-700 dark:hover:text-red-300 transition-colors"
                            >
                                {t('settings.apiKeyTest.status.error.invalidKey.linkText')}
                            </a>
                            {t('settings.apiKeyTest.status.error.invalidKey.end')}
                        </p>
                    );
                }
                return <p className="text-sm text-red-500 dark:text-red-400">{t('settings.apiKeyTest.status.error.generic', { message: errorMessage })}</p>;
            default:
                return null;
        }
    };

    return (
        <div>
            <div className="flex flex-col sm:flex-row gap-2">
                <input
                    type="password"
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    placeholder={t('settings.apiKeyTest.placeholder')}
                    className="flex-grow w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2"
                />
                <button
                    onClick={handleTestKey}
                    disabled={status === 'testing' || !apiKey}
                    className="px-4 py-2 bg-indigo-600 text-white rounded-md font-semibold hover:bg-indigo-700 transition-colors disabled:bg-indigo-400 dark:disabled:bg-gray-600"
                >
                    {buttonText || t('settings.apiKeyTest.button')}
                </button>
            </div>
            <div className="mt-2 min-h-[20px]">
                {getStatusMessage()}
            </div>
        </div>
    );
};

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangleIcon } from './Icons';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

/**
 * Standard React Error Boundary component.
 * Uses a class component as functional components cannot be error boundaries yet.
 */
// FIX: Explicitly inheriting from React.Component with generic Props and State types ensures 'this.props' and 'this.state' are recognized by TypeScript.
export class ErrorBoundary extends React.Component<Props, State> {
  // FIX: Define state as a class property for cleaner initialization and better TypeScript inference.
  public state: State = {
    hasError: false,
    error: null,
  };

  // Static method to update state when an error occurs
  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  // Lifecycle method to catch errors and log them
  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  // Simple reload function for the UI button
  private handleReload = () => {
    window.location.reload();
  };

  public render() {
    // FIX: Accessing this.state is now safe as ErrorBoundary inherits from React.Component<Props, State>
    if (this.state.hasError) {
      return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-900 p-4 text-center">
          <div className="bg-white dark:bg-gray-800 p-8 rounded-2xl shadow-xl max-w-md w-full border border-gray-100 dark:border-gray-700">
            <div className="flex justify-center mb-6">
                <div className="p-4 bg-red-100 dark:bg-red-900/30 rounded-full">
                    <AlertTriangleIcon className="w-12 h-12 text-red-600 dark:text-red-400" />
                </div>
            </div>
            <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">Ups, etwas ist schiefgelaufen.</h1>
            <p className="text-gray-600 dark:text-gray-400 mb-6 text-sm">
              Die App ist auf einen unerwarteten Fehler gestoßen. Wir haben dies protokolliert.
            </p>

            {/* FIX: Safely accessing this.state.error after ensuring correct component typing */}
            {this.state.error && (
                <div className="mb-6 p-3 bg-gray-100 dark:bg-gray-900 rounded text-xs text-left font-mono text-red-500 overflow-auto max-h-32">
                    {this.state.error.toString()}
                </div>
            )}

            <button
              onClick={this.handleReload}
              className="w-full py-3 px-6 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-xl transition-colors shadow-md"
            >
              App neu laden
            </button>
          </div>
        </div>
      );
    }

    // FIX: Accessing this.props now correctly resolves within the typed Component context
    return this.props.children;
  }
}

