export const findNearbyRestaurants = async (latitude: number, longitude: number): Promise<{ name: string; cuisine?: string }[]> => {
    try {
        const gemini = getAiClient();
        // FIX: Google Maps grounding is only supported in Gemini 2.5 series models. 
        // Using 'gemini-2.5-flash' explicitly for this tool.
        const response = await gemini.models.generateContent({
            model: "gemini-2.5-flash",
            contents: "List good restaurants nearby.",
            config: {
                tools: [{ googleMaps: {} }],
                toolConfig: {
                    retrievalConfig: {
                        latLng: {
                            latitude,
                            longitude
                        }
                    }
                },
            },
        });

        const restaurants: { name: string; cuisine?: string }[] = [];
        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

        if (chunks) {
            chunks.forEach((chunk: any) => {
                if (chunk.maps && chunk.maps.title) {
                    restaurants.push({
                        name: chunk.maps.title,
                    });
                }
            });
        }

        return restaurants;
    } catch (error) {
        console.error("Failed to find nearby restaurants:", error);
        return [];
    }
};

import { Type, GoogleGenAI } from "@google/genai";
import { getAiClient, hasValidApiKey } from './geminiService';

const CACHE_KEY = 'food_tracker_translation_cache';
const SOURCE_LANGUAGE = 'en';
const BATCH_DELAY_MS = 100;

const loadCache = (): Record<string, Record<string, string>> => {
    try {
        const stored = localStorage.getItem(CACHE_KEY);
        return stored ? JSON.parse(stored) : {};
    } catch (e) { return {}; }
};

const saveCache = (cache: Record<string, Record<string, string>>) => {
    try { localStorage.setItem(CACHE_KEY, JSON.stringify(cache)); } catch (e) {}
};

const memoryCache: Record<string, Record<string, string>> = loadCache();

interface PendingRequest {
    text: string;
    targetLang: 'de';
    resolve: (translated: string) => void;
}

let pendingQueue: PendingRequest[] = [];
let batchTimeout: ReturnType<typeof setTimeout> | null = null;

const processBatch = async () => {
    if (pendingQueue.length === 0) return;

    const currentBatch = [...pendingQueue];
    pendingQueue = [];
    batchTimeout = null;

    const uniqueTexts = Array.from(new Set(currentBatch.map(r => r.text))).filter(t => !memoryCache['de']?.[t]);

    if (uniqueTexts.length === 0) {
        currentBatch.forEach(req => req.resolve(memoryCache['de'][req.text] || req.text));
        return;
    }

    try {
        const gemini = getAiClient();
        // FIX: Updated model to gemini-3-flash-preview for basic text tasks.
        const response = await gemini.models.generateContent({
            model: "gemini-3-flash-preview",
            config: {
                temperature: 0, 
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        translations: {
                            type: Type.ARRAY,
                            items: {
                                type: Type.OBJECT,
                                properties: {
                                    original: { type: Type.STRING },
                                    translated: { type: Type.STRING }
                                },
                                required: ["original", "translated"]
                            }
                        }
                    }
                }
            },
            contents: { parts: [{ text: `Translate to German: ${JSON.stringify(uniqueTexts)}` }] },
        });

        // FIX: Accessing .text directly.
        const json = JSON.parse(response.text || '{"translations":[]}');
        const mapping: Record<string, string> = {};
        json.translations?.forEach((t: any) => mapping[t.original] = t.translated);

        if (!memoryCache['de']) memoryCache['de'] = {};
        uniqueTexts.forEach(text => memoryCache['de'][text] = mapping[text] || text);
        saveCache(memoryCache);

        currentBatch.forEach(req => req.resolve(memoryCache['de'][req.text] || req.text));
    } catch (error) {
        currentBatch.forEach(req => req.resolve(req.text));
    }
};

export const translateTexts = async (texts: (string | undefined | null)[], targetLang: 'en' | 'de'): Promise<string[]> => {
    if (targetLang === SOURCE_LANGUAGE || !texts.length || !hasValidApiKey()) {
        return texts.map(t => t || '');
    }

    const results: string[] = new Array(texts.length);
    const promises: Promise<void>[] = [];

    texts.forEach((text, index) => {
        const val = text?.trim() || '';
        if (!val) { results[index] = ''; return; }
        if (memoryCache[targetLang]?.[val]) { results[index] = memoryCache[targetLang][val]; return; }

        promises.push(new Promise<string>((resolve) => {
            pendingQueue.push({ text: val, targetLang: 'de', resolve });
        }).then(t => { results[index] = t; }));
    });

    if (pendingQueue.length > 0 && !batchTimeout) {
        batchTimeout = setTimeout(processBatch, BATCH_DELAY_MS);
    }

    if (promises.length > 0) await Promise.all(promises);
    return results;
};

import React, { useState, useCallback } from 'react';
import { GoogleGenAI } from '@google/genai';
import { useTranslation } from '../i18n/index';
import { SparklesIcon } from './Icons';

interface ApiKeyTesterProps {
    onKeyVerified: (apiKey: string) => void;
    buttonText?: string;
}

export const ApiKeyTester: React.FC<ApiKeyTesterProps> = ({ onKeyVerified, buttonText }) => {
    const { t } = useTranslation();
    const [apiKey, setApiKey] = useState('');
    const [status, setStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
    const [errorMessage, setErrorMessage] = useState<string | null>(null);
    const [isInvalidKeyError, setIsInvalidKeyError] = useState(false);

    const handleTestKey = useCallback(async () => {
        const keyToTest = apiKey.trim();
        if (!keyToTest) return;

        setStatus('testing');
        setErrorMessage(null);
        setIsInvalidKeyError(false);

        try {
            const testAi = new GoogleGenAI({ apiKey: keyToTest });
            // FIX: Updated model to gemini-3-flash-preview for connectivity test.
            await testAi.models.generateContent({ 
                model: 'gemini-3-flash-preview', 
                contents: { parts: [{ text: 'hello' }] }
            });

            setStatus('success');
            onKeyVerified(keyToTest);

        } catch (e: any) {
            setStatus('error');

            let message = 'An unknown error occurred.';
            if (e?.error?.message) {
                message = e.error.message;
            } else if (e instanceof Error) {
                message = e.message;
            } else if (typeof e === 'string') {
                message = e;
            }

            if (message.includes('API key not valid') || message.includes('API_KEY_INVALID')) {
                setIsInvalidKeyError(true);
            }

            setErrorMessage(message.replace(/\[\w+\/\w+\]\s*/, ''));
            console.error("API Key Test Failed:", e);
        }
    }, [apiKey, onKeyVerified]);

    const getStatusMessage = () => {
        switch (status) {
            case 'testing':
                return (
                    <div className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                        <SparklesIcon className="w-4 h-4 animate-pulse" />
                        <span>{t('settings.apiKeyTest.status.testing')}</span>
                    </div>
                );
            case 'success':
                return <p className="text-sm text-green-600 dark:text-green-400">{t('settings.apiKeyTest.status.success')}</p>;
            case 'error':
                if (isInvalidKeyError) {
                    return (
                        <p className="text-sm text-red-500 dark:text-red-400">
                            {t('settings.apiKeyTest.status.error.invalidKey.start')}
                            <a 
                                href="https://aistudio.google.com/app/apikey" 
                                target="_blank" 
                                rel="noopener noreferrer" 
                                className="underline hover:text-red-700 dark:hover:text-red-300 transition-colors"
                            >
                                {t('settings.apiKeyTest.status.error.invalidKey.linkText')}
                            </a>
                            {t('settings.apiKeyTest.status.error.invalidKey.end')}
                        </p>
                    );
                }
                return <p className="text-sm text-red-500 dark:text-red-400">{t('settings.apiKeyTest.status.error.generic', { message: errorMessage })}</p>;
            default:
                return null;
        }
    };

    return (
        <div>
            <div className="flex flex-col sm:flex-row gap-2">
                <input
                    type="password"
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    placeholder={t('settings.apiKeyTest.placeholder')}
                    className="flex-grow w-full bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 rounded-md shadow-sm focus:ring-indigo-500 focus:border-indigo-500 text-gray-900 dark:text-white p-2"
                />
                <button
                    onClick={handleTestKey}
                    disabled={status === 'testing' || !apiKey}
                    className="px-4 py-2 bg-indigo-600 text-white rounded-md font-semibold hover:bg-indigo-700 transition-colors disabled:bg-indigo-400 dark:disabled:bg-gray-600"
                >
                    {buttonText || t('settings.apiKeyTest.button')}
                </button>
            </div>
            <div className="mt-2 min-h-[20px]">
                {getStatusMessage()}
            </div>
        </div>
    );
};

